// Complete Form Example
interface FormData {
  name: string;
  email: string;
  role: string;
  description: string;
  notifications: boolean;
}

interface FormExampleProps {
  onSubmit?: (data: FormData) => void;
}

export const FormExample: React.FC<FormExampleProps> = ({ onSubmit }) => {
  const [formData, setFormData] = useState<FormData>({
    name: '',
    email: '',
    role: '',
    description: '',
    notifications: true,
  });
  const [errors, setErrors] = useState<Partial<Record<keyof FormData, string>>>({});

  const validate = (): boolean => {
    const newErrors: Partial<Record<keyof FormData, string>> = {};
    
    if (!formData.name.trim()) {
      newErrors.name = '请输入名称';
    }
    
    if (!formData.email.trim()) {
      newErrors.email = '请输入邮箱';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      newErrors.email = '邮箱格式不正确';
    }
    
    if (!formData.role) {
      newErrors.role = '请选择角色';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      onSubmit?.(formData);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6 max-w-lg">
      <FormSection title="基本信息" description="请填写您的基本信息">
        <FormField label="名称" required error={errors.name}>
          <Input
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
            placeholder="请输入名称"
            state={errors.name ? 'error' : 'default'}
          />
        </FormField>

        <FormField label="邮箱" required error={errors.email}>
          <Input
            type="email"
            value={formData.email}
            onChange={(e) => setFormData({ ...formData, email: e.target.value })}
            placeholder="请输入邮箱"
            state={errors.email ? 'error' : 'default'}
          />
        </FormField>

        <FormField label="角色" required error={errors.role}>
          <Select
            value={formData.role}
            onChange={(value) => setFormData({ ...formData, role: value })}
            options={[
              { value: 'developer', label: '开发者' },
              { value: 'data-scientist', label: '数据科学家' },
              { value: 'product', label: '产品经理' },
              { value: 'researcher', label: '研究员' },
            ]}
            placeholder="请选择角色"
            error={!!errors.role}
          />
        </FormField>
      </FormSection>

      <FormSection title="其他信息">
        <FormField label="描述" helperText="简单描述您的需求">
          <Textarea
            value={formData.description}
            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
            placeholder="请输入描述..."
          />
        </FormField>

        <Switch
          checked={formData.notifications}
          onChange={(checked) => setFormData({ ...formData, notifications: checked })}
          label="接收邮件通知"
        />
      </FormSection>

      <div className="flex gap-3 pt-4">
        <button
          type="submit"
          className="px-4 py-2 rounded-md bg-[var(--color-cta)] text-[var(--color-text-inverse)] font-medium hover:bg-[var(--color-cta-hover)] transition-colors"
        >
          提交
        </button>
        <button
          type="button"
          onClick={() => setFormData({ name: '', email: '', role: '', description: '', notifications: true })}
          className="px-4 py-2 rounded-md border border-[var(--color-border)] text-[var(--color-text-primary)] hover:bg-[var(--color-bg-secondary)] transition-colors"
        >
          重置
        </button>
      </div>
    </form>
  );
};

