// Line Chart
interface ChartDataPoint {
  label: string;
  value: number;
}

interface LineChartProps {
  data: ChartDataPoint[];
  height?: number;
  color?: string;
  showArea?: boolean;
  showDots?: boolean;
  className?: string;
}

export const LineChart: React.FC<LineChartProps> = ({
  data,
  height = 200,
  color = 'var(--color-cta)',
  showArea = true,
  showDots = true,
  className,
}) => {
  const maxValue = Math.max(...data.map((d) => d.value));
  const minValue = Math.min(...data.map((d) => d.value));
  const range = maxValue - minValue || 1;

  const points = data.map((d, i) => ({
    x: (i / (data.length - 1)) * 100,
    y: 100 - ((d.value - minValue) / range) * 100,
  }));

  const pathD = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
  const areaD = `${pathD} L 100 100 L 0 100 Z`;

  return (
    <div className={cn('w-full', className)} style={{ height }}>
      <svg viewBox="0 0 100 100" preserveAspectRatio="none" className="w-full h-full">
        {/* Grid lines */}
        {[0, 25, 50, 75, 100].map((y) => (
          <line key={y} x1="0" y1={y} x2="100" y2={y} stroke="var(--color-border)" strokeWidth="0.2" />
        ))}
        
        {/* Area fill */}
        {showArea && (
          <path d={areaD} fill={color} fillOpacity="0.1" />
        )}
        
        {/* Line */}
        <path d={pathD} fill="none" stroke={color} strokeWidth="0.5" strokeLinecap="round" strokeLinejoin="round" />
        
        {/* Dots */}
        {showDots && points.map((p, i) => (
          <circle
            key={i}
            cx={p.x}
            cy={p.y}
            r="1"
            fill={color}
          />
        ))}
      </svg>
      
      {/* Labels */}
      <div className="flex justify-between mt-2 text-xs text-[var(--color-text-tertiary)]">
        {data.filter((_, i) => i % Math.ceil(data.length / 5) === 0).map((d, i) => (
          <span key={i}>{d.label}</span>
        ))}
      </div>
    </div>
  );
};

// Bar Chart
interface BarChartProps {
  data: ChartDataPoint[];
  height?: number;
  color?: string;
  horizontal?: boolean;
  showValues?: boolean;
  className?: string;
}

export const BarChart: React.FC<BarChartProps> = ({
  data,
  height = 200,
  color = 'var(--color-cta)',
  horizontal,
  showValues,
  className,
}) => {
  const maxValue = Math.max(...data.map((d) => d.value));

  return (
    <div className={cn('w-full', className)} style={{ height }}>
      <div className="flex items-end justify-between gap-2 h-full">
        {data.map((d, i) => {
          const barHeight = (d.value / maxValue) * 100;
          return (
            <div key={i} className="flex-1 flex flex-col items-center gap-1">
              <div className="w-full flex flex-col items-center" style={{ height: '100%' }}>
                {showValues && (
                  <span className="text-xs text-[var(--color-text-secondary)] mb-1">
                    {d.value}
                  </span>
                )}
                <div
                  className="w-full rounded-t transition-all duration-500"
                  style={{
                    height: `${barHeight}%`,
                    backgroundColor: color,
                    opacity: 0.6 + (i / data.length) * 0.4,
                  }}
                />
              </div>
              <span className="text-xs text-[var(--color-text-tertiary)] truncate max-w-full">
                {d.label}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

// Donut / Pie Chart
interface DonutChartProps {
  data: { label: string; value: number; color: string }[];
  size?: number;
  strokeWidth?: number;
  showLegend?: boolean;
  className?: string;
}

export const DonutChart: React.FC<DonutChartProps> = ({
  data,
  size = 200,
  strokeWidth = 20,
  showLegend = true,
  className,
}) => {
  const total = data.reduce((sum, d) => sum + d.value, 0);
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  let offset = 0;

  return (
    <div className={cn('flex items-center gap-6', className)}>
      <div className="relative" style={{ width: size, height: size }}>
        <svg viewBox={`0 0 ${size} ${size}`} className="transform -rotate-90">
          {/* Background circle */}
          <circle
            cx={size / 2}
            cy={size / 2}
            r={radius}
            fill="none"
            stroke="var(--color-bg-tertiary)"
            strokeWidth={strokeWidth}
          />
          
          {/* Data segments */}
          {data.map((d, i) => {
            const percentage = d.value / total;
            const dashLength = circumference * percentage;
            const dashOffset = circumference - offset;
            offset += dashLength;

            return (
              <circle
                key={i}
                cx={size / 2}
                cy={size / 2}
                r={radius}
                fill="none"
                stroke={d.color}
                strokeWidth={strokeWidth}
                strokeDasharray={`${dashLength} ${circumference - dashLength}`}
                strokeDashoffset={dashOffset}
                className="transition-all duration-500"
              />
            );
          })}
        </svg>
        
        {/* Center text */}
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <span className="text-2xl font-bold text-[var(--color-text-primary)]">{total}</span>
          <span className="text-xs text-[var(--color-text-secondary)]">总计</span>
        </div>
      </div>

      {/* Legend */}
      {showLegend && (
        <div className="space-y-2">
          {data.map((d, i) => (
            <div key={i} className="flex items-center gap-2">
              <div className="w-3 h-3 rounded-sm" style={{ backgroundColor: d.color }} />
              <span className="text-sm text-[var(--color-text-primary)]">{d.label}</span>
              <span className="text-xs text-[var(--color-text-tertiary)]">
                ({Math.round((d.value / total) * 100)}%)
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

// Progress Bar
interface ProgressProps {
  value: number;
  max?: number;
  label?: string;
  showValue?: boolean;
  color?: string;
  size?: 'sm' | 'md' | 'lg';
  className?: string;
}

export const Progress: React.FC<ProgressProps> = ({
  value,
  max = 100,
  label,
  showValue = true,
  color = 'var(--color-cta)',
  size = 'md',
  className,
}) => {
  const percentage = Math.min((value / max) * 100, 100);
  const heights = { sm: '4px', md: '8px', lg: '12px' };

  return (
    <div className={cn('w-full', className)}>
      {(label || showValue) && (
        <div className="flex justify-between mb-1">
          {label && <span className="text-sm text-[var(--color-text-primary)]">{label}</span>}
          {showValue && <span className="text-sm text-[var(--color-text-secondary)]">{Math.round(percentage)}%</span>}
        </div>
      )}
      <div className="w-full rounded-full bg-[var(--color-bg-tertiary)] overflow-hidden" style={{ height: heights[size] }}>
        <div
          className="h-full rounded-full transition-all duration-500"
          style={{ width: `${percentage}%`, backgroundColor: color }}
        />
      </div>
    </div>
  );
};

// Stats Card with Mini Chart
interface StatCardProps {
  title: string;
  value: string | number;
  change?: string;
  trend?: 'up' | 'down' | 'neutral';
  chartData?: number[];
  chartColor?: string;
  className?: string;
}

export const StatCard: React.FC<StatCardProps> = ({
  title,
  value,
  change,
  trend,
  chartData,
  chartColor = 'var(--color-cta)',
  className,
}) => {
  const trendColors = {
    up: 'text-[var(--color-success)]',
    down: 'text-[var(--color-error)]',
    neutral: 'text-[var(--color-text-tertiary)]',
  };

  return (
    <div className={cn('p-4 rounded-lg bg-[var(--color-bg-secondary)] border border-[var(--color-border)]', className)}>
      <div className="flex items-start justify-between mb-2">
        <span className="text-sm text-[var(--color-text-secondary)]">{title}</span>
        {change && (
          <span className={cn('text-xs', trendColors[trend || 'neutral'])}>
            {trend === 'up' ? '↑' : trend === 'down' ? '↓' : ''} {change}
          </span>
        )}
      </div>
      <div className="text-2xl font-bold font-[var(--font-heading)] text-[var(--color-text-primary)] mb-2">
        {value}
      </div>
      {chartData && (
        <div className="h-8">
          <LineChart
            data={chartData.map((v, i) => ({ label: String(i), value: v }))}
            height={32}
            color={chartColor}
            showArea={false}
            showDots={false}
          />
        </div>
      )}
    </div>
  );
};

